sealed interface FieldResult<out V> {
  class Success<V>(val value: V) : FieldResult<V>
  class Failure(val exception: ApolloException) : FieldResult<Nothing>
}

val <V> FieldResult<V>.isSuccess: Boolean get() = this is FieldResult.Success
fun <V> FieldResult<V>.getOrElse(fallback: V): V = if (this is FieldResult.Success) value else fallback
fun <V> FieldResult<V>.getOrNull(): V? = if (this is FieldResult.Success) value else null
fun <V> FieldResult<V>.exceptionOrNull(): Exception? = if (this is FieldResult.Failure) exception else null
fun <V> FieldResult<V>.graphQLErrorOrNull(): Error? = (exceptionOrNull() as? ApolloGraphQLException)?.error

fun <V> FieldResult<V>.getOrThrow(): V {
  return when (this) {
    is FieldResult.Success -> value
    is FieldResult.Failure -> throw DefaultApolloException("Field error", exception)
  }
}

abstract class TransacterImpl(driver: SqlDriver) :
  BaseTransacterImpl(driver),
  Transacter {
  override fun transaction(
    noEnclosing: Boolean,
    body: TransactionWithoutReturn.() -> Unit,
  ) {
    transactionWithWrapper<Unit?>(noEnclosing, body)
  }

  override fun <R> transactionWithResult(
    noEnclosing: Boolean,
    bodyWithReturn: TransactionWithReturn<R>.() -> R,
  ): R {
    return transactionWithWrapper(noEnclosing, bodyWithReturn)
  }

  private fun <R> transactionWithWrapper(noEnclosing: Boolean, wrapperBody: TransactionWrapper<R>.() -> R): R {
    val transaction = driver.newTransaction().value
    val enclosing = transaction.enclosingTransaction()

    check(enclosing == null || !noEnclosing) { "Already in a transaction" }

    var thrownException: Throwable? = null
    var returnValue: R? = null

    try {
      transaction.transacter = this
      returnValue = TransactionWrapper<R>(transaction).wrapperBody()
      transaction.successful = true
    } catch (e: Throwable) {
      thrownException = e
    } finally {
      transaction.endTransaction()
      return postTransactionCleanup(transaction, enclosing, thrownException, returnValue)
    }
  }
}

inner class Transaction(
  override val enclosingTransaction: Transacter.Transaction?,
) : Transacter.Transaction() {
  override fun endTransaction(successful: Boolean): QueryResult<Unit> {
    if (enclosingTransaction == null) {
      if (successful) {
        database.setTransactionSuccessful()
        database.endTransaction()
      } else {
        database.endTransaction()
      }
    }
    transactions.set(enclosingTransaction)
    return QueryResult.Unit
  }
}

private fun <T> execute(
  identifier: Int?,
  createStatement: () -> AndroidStatement,
  binders: (SqlPreparedStatement.() -> Unit)?,
  result: AndroidStatement.() -> T,
): QueryResult.Value<T> {
  var statement: AndroidStatement? = null
  if (identifier != null) {
    statement = statements.remove(identifier)
  }
  if (statement == null) {
    statement = createStatement()
  }
  try {
    if (binders != null) {
      statement.binders()
    }
    return QueryResult.Value(statement.result())
  } finally {
    if (identifier != null) {
      statements.put(identifier, statement)?.close()
    } else {
      statement.close()
    }
  }
}

internal class AsyncPublisherIterator<T : Any>(
  pub: Publisher<T>,
) {
  private var nextValue = CompletableDeferred<T?>()
  private val subscription = CompletableDeferred<Subscription>()

  init {
    pub.subscribe(object : Subscriber<T> {
      override fun onSubscribe(sub: Subscription) {
        subscription.complete(sub)
      }

      override fun onError(error: Throwable) {
        nextValue.completeExceptionally(error)
      }

      override fun onComplete() {
        nextValue.complete(null)
      }

      override fun onNext(next: T) {
        nextValue.complete(next)
      }
    })
  }

  suspend fun next(): T? {
    val sub = subscription.await()
    sub.request(1)
    try {
      val next = nextValue.await() ?: return null
      nextValue = CompletableDeferred()
      return next
    } catch (cancel: CancellationException) {
      sub.cancel()
      throw cancel
    }
  }
}

