interface ConnectionManager {
  fun close()

  fun getConnection(): Connection

  fun closeConnection(connection: Connection)

  fun Connection.beginTransaction()

  fun Connection.endTransaction()

  fun Connection.rollbackTransaction()

  var transaction: Transaction?

  class Transaction(
    override val enclosingTransaction: Transaction?,
    private val connectionManager: ConnectionManager,
    val connection: Connection,
  ) : Transacter.Transaction() {
    override fun endTransaction(successful: Boolean): QueryResult<Unit> {
      try {
        if (enclosingTransaction == null) {
          if (successful) {
            connectionManager.apply { connection.endTransaction() }
          } else {
            connectionManager.apply { connection.rollbackTransaction() }
          }
        }
        // properly rotate the transaction even if there are uncaught errors
      } finally {
        connectionManager.transaction = enclosingTransaction
      }
      return QueryResult.Unit
    }
  }
}

package io.mockk.impl.eval

import io.mockk.CapturingSlot
import io.mockk.MockKGateway
import io.mockk.MockKGateway.CallRecorder
import io.mockk.MockKGateway.Stubber
import io.mockk.MockKMatcherScope
import io.mockk.MockKStubScope
import io.mockk.impl.recording.AutoHinter

class EveryBlockEvaluator(
    callRecorder: () -> CallRecorder,
    autoHinterFactory: () -> AutoHinter,
) : RecordedBlockEvaluator(callRecorder, autoHinterFactory),
    Stubber {
    @Suppress("UNCHECKED_CAST")
    override fun <T> every(
        mockBlock: (MockKMatcherScope.() -> T)?,
        coMockBlock: (suspend MockKMatcherScope.() -> T)?,
    ): MockKStubScope<T, T> {
        if (coMockBlock != null) {
            initializeCoroutines()
        }

        callRecorder().startStubbing()

        val lambda = CapturingSlot<Function<*>>()
        val scope = MockKMatcherScope(callRecorder(), lambda)

        record(scope, mockBlock, coMockBlock)

        val opportunity = callRecorder().answerOpportunity() as MockKGateway.AnswerOpportunity<T>

        return MockKStubScope(opportunity, callRecorder(), lambda)
    }
}

package io.mockk.impl.eval

import io.mockk.CapturingSlot
import io.mockk.MockKGateway.CallRecorder
import io.mockk.MockKGateway.VerificationParameters
import io.mockk.MockKGateway.Verifier
import io.mockk.MockKVerificationScope
import io.mockk.impl.recording.AutoHinter
import io.mockk.impl.stub.StubRepository

class VerifyBlockEvaluator(
    callRecorder: () -> CallRecorder,
    val stubRepo: StubRepository,
    autoHinterFactory: () -> AutoHinter,
) : RecordedBlockEvaluator(callRecorder, autoHinterFactory),
    Verifier {
    override fun verify(
        params: VerificationParameters,
        mockBlock: (MockKVerificationScope.() -> Unit)?,
        coMockBlock: (suspend MockKVerificationScope.() -> Unit)?,
    ) {
        if (coMockBlock != null) {
            initializeCoroutines()
        }

        callRecorder().startVerification(params)

        val lambda = CapturingSlot<Function<*>>()
        val scope = MockKVerificationScope(callRecorder(), lambda)

        try {
            record(scope, mockBlock, coMockBlock)
        } finally {
            callRecorder().reset()
        }
    }
}

